3	const BASE_PREMIUMS: Record<string, number> = {
4	  Sword: 100,
5	  Amulet: 60,
6	  Staff: 80,
7	  Potion: 40,
8	  Rune: 25,
9	};
10	
11	const FIRST_INSURANCE_PERCENT = 110;
12	const PROCESSING_FEE = 5;
13	
14	type Item = { type: string };
15	
16	const quotePremium = (items: Item[]): number => {
17	  const baseTotal = items.reduce(
18	    (total, item) => total + BASE_PREMIUMS[item.type],
19	    0,
20	  );
21	  const withFirstInsurance = (baseTotal * FIRST_INSURANCE_PERCENT) / 100;
22	  return Math.ceil(withFirstInsurance + PROCESSING_FEE);
23	};
24	
25	export function processScenario(scenario: any): unknown {
26	  const [{ items }] = scenario.steps;
27	  return { results: [{ premium: quotePremium(items) }] };
28	}
